import{_ as t,o as a,c as r,a4 as o}from"./chunks/framework.DyALjzgy.js";const u=JSON.parse('{"title":"Marketplace","description":"","frontmatter":{},"headers":[],"relativePath":"overview/modules/marketplace.md","filePath":"overview/modules/marketplace.md"}'),s={name:"overview/modules/marketplace.md"};function i(n,e,l,c,d,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="marketplace" tabindex="-1">Marketplace <a class="header-anchor" href="#marketplace" aria-label="Permalink to &quot;Marketplace&quot;">​</a></h1><p>The <strong>Marketplace</strong> is the service-provider discovery and self-service installation hub. It allows workspace users to browse a catalog of available service providers (extensions), view their metadata, and install or uninstall them with a single click.</p><p>Under the hood, installing a provider creates a Kubernetes <code>APIBinding</code> in the current workspace that points at the provider&#39;s <code>APIExport</code>, granting the workspace access to the provider&#39;s APIs and controllers.</p><h2 id="marketplace-ui" tabindex="-1">Marketplace UI <a class="header-anchor" href="#marketplace-ui" aria-label="Permalink to &quot;Marketplace UI&quot;">​</a></h2><p>The <strong>Marketplace UI</strong> is an Angular microfrontend application that serves as the service-provider discovery and management hub within the <strong>Platform Mesh</strong> ecosystem. It enables users to browse, install, and uninstall service providers (extensions) into their Platform Mesh workspace.</p><hr><h3 id="what-is-platform-mesh-and-what-role-does-the-marketplace-ui-play" tabindex="-1">What Is Platform Mesh and what role does the Marketplace UI play? <a class="header-anchor" href="#what-is-platform-mesh-and-what-role-does-the-marketplace-ui-play" aria-label="Permalink to &quot;What Is Platform Mesh and what role does the Marketplace UI play?&quot;">​</a></h3><p>Platform Mesh is a multi-cluster, multi-tenant platform built on top of <a href="https://kcp.io" target="_blank" rel="noreferrer">kcp</a> — a Kubernetes control-plane layer that introduces <strong>workspaces</strong> as isolated, lightweight &quot;clusters.&quot; Rather than deploying everything into a single monolithic cluster, Platform Mesh organizes resources across hierarchical workspaces (accounts → projects → teams).</p><h4 id="providers-and-the-apiexport-apibinding-model" tabindex="-1">Providers and the APIExport / APIBinding Model <a class="header-anchor" href="#providers-and-the-apiexport-apibinding-model" aria-label="Permalink to &quot;Providers and the APIExport / APIBinding Model&quot;">​</a></h4><p>The central mechanism for service delivery in Platform Mesh is the <strong>provider/consumer model</strong>:</p><ul><li>A <strong>Service Provider</strong> (or &quot;extension&quot;) is a team or product that wants to offer capabilities (APIs, controllers, storage, tooling) to other workspaces in the platform.</li><li>The provider creates an <strong><code>APIExport</code></strong> in their workspace — a packaged, versioned set of custom Kubernetes APIs (CRDs + permission claims) that they want to share.</li><li>A consumer workspace that wants to use those capabilities creates an <strong><code>APIBinding</code></strong> pointing at the provider&#39;s <code>APIExport</code>. Once bound, the consumer workspace gets access to the provider&#39;s APIs and the provider&#39;s controllers can act on the consumer&#39;s resources.</li></ul><p>This model allows providers to operate their controllers centrally while serving many consumer workspaces without installing CRDs in each one.</p><h4 id="the-marketplace" tabindex="-1">The Marketplace <a class="header-anchor" href="#the-marketplace" aria-label="Permalink to &quot;The Marketplace&quot;">​</a></h4><p>The <strong>Marketplace</strong> is the catalog layer on top of this mechanism. It stores <strong><code>MarketplaceEntry</code></strong> custom resources — one per registered provider — that bundle:</p><ul><li>The provider&#39;s <code>APIExport</code> reference (what is being offered)</li><li><code>ProviderMetadata</code> (display name, description, icon, contacts, documentation, support channels, service level, verification status, tags)</li><li>Installation state (whether the current workspace already has an <code>APIBinding</code> for this provider)</li></ul><p>The Marketplace UI queries this catalog and lets users install or uninstall providers with a single click, which translates directly into creating or deleting the corresponding <code>APIBinding</code> in their workspace.</p><hr><h3 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Provider catalog</td><td>Browsable, searchable, filterable list of all available service providers</td></tr><tr><td>Provider details</td><td>Full metadata view: description, contacts, documentation, support channels, service level</td></tr><tr><td>Install</td><td>Creates an <code>APIBinding</code> in the current workspace with all required permission claims auto-accepted</td></tr><tr><td>Uninstall</td><td>Deletes the <code>APIBinding</code> after a confirmation dialog</td></tr><tr><td>Theme support</td><td>Renders provider icons in light or dark variants based on the active SAP Fiori theme</td></tr><tr><td>Analytics</td><td>Tracks view / install / uninstall events via Matomo</td></tr><tr><td>&quot;New&quot; badge</td><td>Providers created less than 3 months ago are automatically tagged as new</td></tr></tbody></table><hr>',20)])])}const m=t(s,[["render",i]]);export{u as __pageData,m as default};
